import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerVentas } from '../services/ventaService';

const Reportes = () => {
    const navigate = useNavigate();
    const [todasLasVentas, setTodasLasVentas] = useState([]);
    const [filtro, setFiltro] = useState('dia');
    const [busquedaFecha, setBusquedaFecha] = useState(new Date().toISOString().split('T')[0]);
    const [textoBusqueda, setTextoBusqueda] = useState(''); // ✅ Nuevo: Buscar por vendedor o producto

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            cargarDatos();
        }
    }, [navigate]);

    const cargarDatos = async () => {
        const data = await obtenerVentas();
        if (data) setTodasLasVentas(data);
    };

    // ✅ FILTRADO INSTANTÁNEO (Sin esperar a efectos secundarios)
    const fechaRef = new Date(busquedaFecha + "T12:00:00");
    
    const ventasFiltradas = todasLasVentas.filter(v => {
        const fechaV = new Date(
            Array.isArray(v.fechaVenta)
                ? `${v.fechaVenta[0]}-${String(v.fechaVenta[1]).padStart(2,'0')}-${String(v.fechaVenta[2]).padStart(2,'0')}T${String(v.fechaVenta[3]).padStart(2,'0')}:${String(v.fechaVenta[4]).padStart(2,'0')}:00`
                : v.fechaVenta
        );

        // Filtro por tiempo
        const coincideTiempo = filtro === 'dia' 
            ? (fechaV.toDateString() === fechaRef.toDateString())
            : filtro === 'mes'
            ? (fechaV.getMonth() === fechaRef.getMonth() && fechaV.getFullYear() === fechaRef.getFullYear())
            : (fechaV.getFullYear() === fechaRef.getFullYear());

        // Filtro por texto (Vendedor o Producto)
        const coincideTexto = v.vendedorMatricula.toLowerCase().includes(textoBusqueda.toLowerCase()) ||
                             v.nombreProducto.toLowerCase().includes(textoBusqueda.toLowerCase());

        return coincideTiempo && coincideTexto;
    });

    // Totales calculados sobre la lista filtrada
    const totalVendido = ventasFiltradas.reduce((acc, v) => acc + (v.total || 0), 0);
    const totalGastos = ventasFiltradas.reduce((acc, v) => acc + ((v.precioCompra || 0) * (v.cantidad || 0)), 0);
    const gananciaNeta = totalVendido - totalGastos;

    const formatearFecha = (fv) => {
        try {
            if (Array.isArray(fv)) return `${String(fv[3]).padStart(2,'0')}:${String(fv[4]).padStart(2,'0')}`;
            return new Date(fv).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        } catch { return '--:--'; }
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '1200px', margin: '0 auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <button onClick={() => navigate("/inventario")} style={{ backgroundColor: '#6c757d', color: 'white', padding: '10px 15px', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>⬅️ Inventario</button>
                <h2 style={{ color: '#007bff', margin: 0 }}>📈 Reporte Financiero</h2>
            </div>

            {/* PANEL DE FILTROS */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1.5fr auto', gap: '15px', background: '#fff', padding: '20px', borderRadius: '15px', marginBottom: '25px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', alignItems: 'flex-end' }}>
                <div>
                    <label><b>Vista:</b></label>
                    <select value={filtro} onChange={(e) => setFiltro(e.target.value)} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ddd', marginTop: '5px' }}>
                        <option value="dia">Día</option>
                        <option value="mes">Mes</option>
                        <option value="año">Año</option>
                    </select>
                </div>
                <div>
                    <label><b>Fecha:</b></label>
                    <input type="date" value={busquedaFecha} onChange={(e) => setBusquedaFecha(e.target.value)} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ddd', marginTop: '5px' }} />
                </div>
                <div>
                    <label><b>Buscar Vendedor/Producto:</b></label>
                    <input type="text" placeholder="Ej: riempy o Funda..." value={textoBusqueda} onChange={(e) => setTextoBusqueda(e.target.value)} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #007bff', marginTop: '5px' }} />
                </div>
                <button onClick={cargarDatos} style={{ backgroundColor: '#007bff', color: 'white', padding: '12px 20px', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>🔄</button>
            </div>

            {/* TARJETAS DE MÉTRICAS */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginBottom: '30px' }}>
                <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '15px', borderLeft: '5px solid #007bff', textAlign: 'center' }}>
                    <span style={{ fontSize: '13px', color: '#666' }}>VENTA TOTAL</span>
                    <h2 style={{ color: '#007bff', margin: '5px 0' }}>${totalVendido.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
                <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '15px', borderLeft: '5px solid #dc3545', textAlign: 'center' }}>
                    <span style={{ fontSize: '13px', color: '#666' }}>GASTO INVERSIÓN</span>
                    <h2 style={{ color: '#dc3545', margin: '5px 0' }}>${totalGastos.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
                <div style={{ background: '#e8f5e9', padding: '20px', borderRadius: '15px', borderLeft: '5px solid #28a745', textAlign: 'center' }}>
                    <span style={{ fontSize: '13px', color: '#2e7d32' }}>UTILIDAD NETA</span>
                    <h2 style={{ color: '#28a745', margin: '5px 0' }}>${gananciaNeta.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
            </div>

            {/* TABLA DE RESULTADOS */}
            <div style={{ background: 'white', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead style={{ background: '#343a40', color: 'white' }}>
                        <tr>
                            <th style={{ padding: '15px' }}>Hora</th>
                            <th style={{ textAlign: 'left' }}>Producto</th>
                            <th>Cant.</th>
                            <th>Vendedor</th>
                            <th>Venta</th>
                            <th>Utilidad</th>
                        </tr>
                    </thead>
                    <tbody>
                        {ventasFiltradas.length > 0 ? ventasFiltradas.map((v, i) => (
                            <tr key={i} style={{ borderBottom: '1px solid #eee', textAlign: 'center' }}>
                                <td style={{ padding: '12px' }}>{formatearFecha(v.fechaVenta)}</td>
                                <td style={{ textAlign: 'left', paddingLeft: '15px' }}>{v.nombreProducto}</td>
                                <td>{v.cantidad}</td>
                                <td><mark style={{ background: '#e7f3ff', padding: '2px 8px', borderRadius: '4px' }}>{v.vendedorMatricula}</mark></td>
                                <td style={{ fontWeight: 'bold' }}>${(v.total || 0).toFixed(2)}</td>
                                <td style={{ color: '#28a745', fontWeight: 'bold' }}>
                                    +${((v.total || 0) - ((v.precioCompra || 0) * (v.cantidad || 0))).toFixed(2)}
                                </td>
                            </tr>
                        )) : (
                            <tr><td colSpan="6" style={{ padding: '40px', color: '#999', textAlign: 'center' }}>No se encontraron registros.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Reportes;
